 604→
 605→    const createItemMutation = useMutation({
 606→        mutationFn: ({payload}) => createFreedomWallItem(authToken, payload),
 607→        onMutate: async({payload}) => {
 608→            const optimisticId = `optimistic-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
 609→            const optimisticItem = {
 610→                id: optimisticId,
 611→                week_id: payload.weekId,
 612→                user_id: currentUserId,
 613→                item_type: payload.itemType,
 614→                payload: payload.payload,
 615→                z_index: payload.zIndex || 0,
 616→                created_at: new Date().toISOString(),
 617→                updated_at: new Date().toISOString(),
 618→                deleted_at: null,
 619→                users: currentUser ? {
