 622→                    image_url: currentUser.image_url,
 623→                    badge: currentUser.badge
 624→                } : null
 625→            };
 626→
 627→            setItemsCache((items) => [...items, optimisticItem]);
 628→
 629→            const itemPayload = payload.payload;
 630→            let pxX, pxY;
 631→            if(payload.itemType === "doodle" && Array.isArray(itemPayload.points) && itemPayload.points.length >= 4){
 632→                const pts = itemPayload.points;
 633→                const midIdx = Math.floor(pts.length / 2);
 634→                const midXIdx = midIdx % 2 === 0 ? midIdx : midIdx - 1;
 635→                pxX = (pts[midXIdx] || 0.5) * stageWidth;
 636→                pxY = (pts[midXIdx + 1] || 0.5) * stageHeight;
 637→            } else {
 638→                pxX = (itemPayload.x || 0.5) * stageWidth;
 639→                pxY = (itemPayload.y || 0.5) * stageHeight;
 640→            }
 641→            setPlacementPuffs((prev) => [...prev, {id: optimisticId, x: pxX, y: pxY, startedAt: Date.now()}]);
 642→
 643→            return {optimisticId: optimisticId};
 644→        },
 645→        onSuccess: (response, _variables, context) => {
 646→            const createdItem = response?.item;
 647→            if(!createdItem?.id){
 648→                return;
 649→            }
 650→
 651→            setItemsCache((items) => {
 652→                const withoutOptimistic = context?.optimisticId
 653→                    ? removeById(items, context.optimisticId)
 654→                    : items;
 655→                return upsertById(withoutOptimistic, createdItem);
 656→            });
 657→        },
 658→        onError: (error, variables, context) => {
 659→            console.error("Freedom Wall create error:", error, "variables:", variables);
 660→            if(context?.optimisticId){
 661→                setItemsCache((items) => removeById(items, context.optimisticId));
 662→            }
