 666→        }
 667→    });
 668→
 669→    const updateItemMutation = useMutation({
 670→        mutationFn: ({itemId, payload}) => updateFreedomWallItem(authToken, itemId, payload),
 671→        onMutate: async({itemId, payload}) => {
 672→            let previousItem = null;
 673→            setItemsCache((items) => {
