 677→                }
 678→
 679→                return items.map((item) => {
 680→                    if(String(item?.id) !== String(itemId)){
 681→                        return item;
 682→                    }
 683→
 684→                    const mergedPayload = payload?.payload !== undefined
 685→                        ? {...(item?.payload || {}), ...(payload.payload || {})}
 686→                        : item?.payload;
 687→
 688→                    return {
 689→                        ...item,
 690→                        payload: mergedPayload,
 691→                        z_index: payload?.zIndex !== undefined ? payload.zIndex : item?.z_index
 692→                    };
 693→                });
 694→            });
 695→            return {previousItem: previousItem};
 696→        },
 697→        onSuccess: (response) => {
 698→            const updatedItem = response?.item;
 699→            if(!updatedItem?.id){
 700→                return;
 701→            }
 702→
 703→            setItemsCache((items) => upsertById(items, updatedItem));
 704→        },
 705→        onError: (_error, variables, context) => {
 706→            if(!context?.previousItem){
 707→                return;
 708→            }
 709→
 710→            setItemsCache((items) => upsertById(items, context.previousItem));
 711→            if(variables?.itemId){
