const handleCursorBroadcast = useCallback((event) => {
    if(!canWrite || !realtimeChannelRef.current) return;

    const now = Date.now();
    if(now - lastCursorBroadcastRef.current < 80) return;
    lastCursorBroadcastRef.current = now;

