                                        key={stampKey}
                                        type="button"
                                        className={`fw-stamp-btn ${draftStamp.stamp === stampKey ? "is-active" : ""}`}
                                        onClick={() => setDraftStamp((prev) => ({...prev, stamp: stampKey}))}
                                    >
                                        {icon}
