            <Circle radius={5} fill={color} opacity={0.85} />
            <Text
                x={8}
                y={4}
                text={displayName}
                fontSize={11}
                fill={color}
                fontStyle="bold"
                opacity={0.8}
            />
        </Group>
    );
};

const formatWeekLabel = (week = null) => {
    if(!week?.week_start || !week?.week_end){
        return "No active week";
    }

    const startDate = new Date(week.week_start);
    const endDate = new Date(week.week_end);
